const response = $input.first().json;
const content = response.content && response.content[0] ? response.content[0].text : '';

let sql = content.trim();
if (sql.startsWith('```')) {
  sql = sql.replace(/^```(?:sql)?\n?/, '').replace(/\n?```$/, '').trim();
}

const upper = sql.toUpperCase();
const forbidden = ['INSERT', 'UPDATE', 'DELETE', 'DROP', 'ALTER', 'CREATE', 'TRUNCATE', 'GRANT', 'REVOKE', 'COPY'];
let found = null;
for (const word of forbidden) {
  const regex = new RegExp('\\b' + word + '\\b');
  if (regex.test(upper)) {
    found = word;
    break;
  }
}

if (found) {
  return [{ json: { error: 'Refused: query contains forbidden keyword ' + found + '. Only SELECT queries are allowed.', valid: false } }];
}

if (!upper.trimStart().startsWith('SELECT') && !upper.trimStart().startsWith('WITH')) {
  return [{ json: { error: 'Refused: query must start with SELECT or WITH.', valid: false } }];
}

if (!upper.includes('LIMIT')) {
  sql = sql.replace(/;\s*$/, '') + ' LIMIT 5000;';
}

return [{ json: { sql, valid: true } }];

const rows = $input.all().map(item => item.json);
